mapper.select:
with query as ( select plainto_tsquery(cast(#{tsConfig} as regconfig), #{question}) as tsq ) select a.source_id, a.article_key as item_key, a.concept_id, a.title, ac.chunk_text as content, a.metadata_json::text as metadata_json, a.review_status, a.source_paths, ac.chunk_index, null::boolean as verbatim, ts_rank_cd(ac.search_tsv, query.tsq)
+ case when lower(ac.chunk_text) like #{likeToken} then 3.0 else 0 end + case when lower(a.title) like #{likeToken} then 1.5 else 0 end + case when lower(a.concept_id) like #{likeToken} then 1.0 else 0 end
as score from article_chunks ac join articles a on a.id = ac.article_id cross join query where ac.search_tsv @@ query.tsq
or lower(ac.chunk_text) like #{likeToken} or lower(a.title) like #{likeToken} or lower(a.concept_id) like #{likeToken}
order by score desc, a.compiled_at desc, a.article_key asc, ac.chunk_index asc limit #{limit}
